import React from 'react';
import axios from 'axios';

function NoteList({ notes, fetchNotes }) {
  const deleteNote = async (id) => {
    await axios.delete(`http://localhost:5001/api/notes/${id}`);
    fetchNotes();
  };

  const cardStyle = {
    background: '#ffffff',
    borderRadius: '16px',
    padding: '24px',
    marginBottom: '20px',
    border: '1px solid #e2e8f0',
    boxShadow: '0 1px 3px rgba(0,0,0,0.05)',
    transition: 'transform 0.2s, box-shadow 0.2s'
  };

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' }}>
      {notes.map((note) => (
        <div 
          key={note._id} 
          style={cardStyle}
          onMouseEnter={(e) => { e.currentTarget.style.transform = 'translateY(-4px)'; e.currentTarget.style.boxShadow = '0 10px 20px rgba(0,0,0,0.05)'; }}
          onMouseLeave={(e) => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 1px 3px rgba(0,0,0,0.05)'; }}
        >
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
            <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '700' }}>{note.title}</h3>
            <button 
              onClick={() => deleteNote(note._id)}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}
              title="Delete"
            >
              ✕
            </button>
          </div>
          <p style={{ color: '#64748b', fontSize: '14px', lineHeight: '1.6', margin: 0 }}>{note.content}</p>
          <div style={{ marginTop: '20px', fontSize: '11px', fontWeight: '700', color: '#cbd5e1', textTransform: 'uppercase' }}>
            {new Date().toLocaleDateString()}
          </div>
        </div>
      ))}
    </div>
  );
}

export default NoteList;
